import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { BookOpen, Target, TrendingUp, Timer, BarChart2, ArrowLeft } from 'lucide-react';
import { initNutriCore, getProfile } from './db';
import FoodDbDownloader, { isFoodDbReady } from './FoodDbDownloader';
import DiaryScreen    from './DiaryScreen';
import TrendsScreen   from './TrendsScreen';
import FastingScreen  from './FastingScreen';
import GoalsScreen    from './GoalsScreen';
import DataTab        from './DataTab';
import OnboardingModal from './OnboardingModal';
import './NutriCore.css';

const TABS = [
  { id: 'diary',   label: 'Diary',   Icon: BookOpen   },
  { id: 'trends',  label: 'Trends',  Icon: TrendingUp },
  { id: 'fasting', label: 'Fasting', Icon: Timer      },
  { id: 'data',    label: 'Data',    Icon: BarChart2  },
  { id: 'goals',   label: 'Goals',   Icon: Target     },
];

const TAB_SUBTITLES = {
  diary:   'Food Diary',
  trends:  'Calorie & Weight',
  fasting: 'Fasting Timer',
  data:    'Nutrient Report',
  goals:   'Goals & Profile',
};

export default function NutriCoreApp() {
  const [tab,         setTab]         = useState('diary');
  const [ready,       setReady]       = useState(false);
  const [onboarding,  setOnboarding]  = useState(false);
  const [initError,   setInitError]   = useState(null);
  const [needsFoodDb, setNeedsFoodDb] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    (async () => {
      try {
        await initNutriCore();
        const profile = await getProfile();
        if (!profile.onboardingComplete) setOnboarding(true);
        setNeedsFoodDb(!isFoodDbReady());
        setReady(true);
      } catch (err) {
        console.error('NutriCore init failed:', err);
        setInitError(err?.message || 'Startup failed');
        setReady(true);
      }
    })();
  }, []);

  if (!ready) {
    return (
      <div className="app-shell nc-app">
        <div className="nc-loader">Setting up NutriCore…</div>
      </div>
    );
  }

  if (initError) {
    return (
      <div className="app-shell nc-app" style={{ alignItems: 'center', justifyContent: 'center', gap: 16, padding: 32 }}>
        <div style={{ fontSize: 15, color: 'var(--nc-warn)', textAlign: 'center' }}>Failed to open database</div>
        <div style={{ fontSize: 12, color: 'var(--nc-text3)', textAlign: 'center' }}>{initError}</div>
        <button className="nc-save-btn" style={{ width: 'auto', padding: '10px 24px' }}
          onClick={() => window.location.reload()}>Reload</button>
      </div>
    );
  }

  return (
    <div className="app-shell nc-app">
      {/* Top bar */}
      <div style={{
        display: 'flex', alignItems: 'center',
        padding: 'calc(env(safe-area-inset-top, 0px) + 10px) 16px 10px',
        background: 'var(--nc-surf)', borderBottom: '1px solid var(--nc-border)',
        flexShrink: 0,
      }}>
        <button className="nc-back-btn" style={{ padding: 0, marginRight: 8 }} onClick={() => navigate('/')}>
          <ArrowLeft size={18} />
        </button>
        <span style={{ fontSize: 17, fontWeight: 700, color: 'var(--nc-text)', flex: 1 }}>
          NutriCore
        </span>
        <span style={{ fontSize: 11, color: 'var(--nc-accent)', fontWeight: 600 }}>
          {TAB_SUBTITLES[tab]}
        </span>
      </div>

      {/* Screen */}
      <div style={{ flex: 1, position: 'relative', overflow: 'hidden' }}>
        {tab === 'diary'   && <DiaryScreen />}
        {tab === 'trends'  && <TrendsScreen />}
        {tab === 'fasting' && <FastingScreen />}
        {tab === 'data'    && <DataTab />}
        {tab === 'goals'   && <GoalsScreen />}
      </div>

      {/* Bottom nav */}
      <nav className="nc-nav">
        {TABS.map(({ id, label, Icon }) => (
          <button key={id}
            className={`nc-nav-btn${tab === id ? ' active' : ''}`}
            onClick={() => setTab(id)}>
            <Icon size={18} />
            {label}
          </button>
        ))}
      </nav>

      {/* Onboarding */}
      {onboarding && (
        <OnboardingModal onComplete={() => setOnboarding(false)} />
      )}

      {/* One-time food database download */}
      {needsFoodDb && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 200 }}>
          <FoodDbDownloader onDone={() => setNeedsFoodDb(false)} />
        </div>
      )}
    </div>
  );
}
