// ── Helpers ──────────────────────────────────────────────────────────────────

function genId() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2);
}

function makeEmptyRoutine() {
  return {
    id: genId(),
    title: '',
    defaultRest: 90,
    exercises: [],
    createdAt: new Date().toISOString(),
  };
}

function makeEmptyExercise(ex) {
  return {
    id: ex.id ?? genId(),
    name: ex.name,
    bodyPart: ex.bodyPart ?? '',
    equipment: ex.equipment ?? '',
    trackingType: ex.trackingType ?? 'reps',
    sets: [{ reps: '', weight: '' }],
  };
}

// ── RoutineCard ───────────────────────────────────────────────────────────────

function RoutineCard({ routine, lastDate, onStart, onEdit, onDelete }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);
  const menuRef = useRef(null);

  const exerciseCount = routine.exercises?.length ?? 0;
  const chips = (routine.exercises ?? []).slice(0, 4);
  const lastLabel = lastDate ? fmtDate(lastDate) : 'Never';

  useEffect(() => {
    if (!menuOpen) return;
    function handle(e) {
      if (menuRef.current && !menuRef.current.contains(e.target)) {
        setMenuOpen(false);
        setConfirmDelete(false);
      }
    }
    document.addEventListener('mousedown', handle);
    document.addEventListener('touchstart', handle);
    return () => {
      document.removeEventListener('mousedown', handle);
      document.removeEventListener('touchstart', handle);
    };
  }, [menuOpen]);

  function handleDeleteClick() {
    if (confirmDelete) {
      onDelete();
      setMenuOpen(false);
      setConfirmDelete(false);
    } else {
      setConfirmDelete(true);
    }
  }

  return (
    <div style={styles.routineCard}>
      {/* Three-dot menu */}
      <div ref={menuRef} style={styles.menuWrap}>
        <button
          style={styles.iconBtn}
          onClick={e => {
            e.stopPropagation();
            setMenuOpen(o => !o);
            setConfirmDelete(false);
          }}
          aria-label="More options"
        >
          <MoreVertical size={16} color="#9CA3AF" />
        </button>
        {menuOpen && (
          <div style={styles.dropMenu}>
            {confirmDelete ? (
              <div style={{ padding: '8px 14px' }}>
                <div style={{ fontSize: 12, color: '#F87171', marginBottom: 8 }}>
                  Delete this routine?
                </div>
                <div style={{ display: 'flex', gap: 8 }}>
                  <button style={styles.confirmBtn} onClick={handleDeleteClick}>
                    Delete
                  </button>
                  <button
                    style={styles.cancelBtn}
                    onClick={() => setConfirmDelete(false)}
                  >
                    Cancel
                  </button>
                </div>
              </div>
            ) : (
              <button style={styles.menuItem} onClick={handleDeleteClick}>
                <Trash2 size={14} color="#F87171" />
                <span style={{ color: '#F87171' }}>Delete</span>
              </button>
            )}
          </div>
        )}
      </div>

      {/* Card body */}
      <div style={styles.routineTitle}>{routine.title || 'Untitled Routine'}</div>
      <div style={styles.routineSub}>
        {exerciseCount} {exerciseCount === 1 ? 'exercise' : 'exercises'} · Last:{' '}
        {lastLabel}
      </div>

      {chips.length > 0 && (
        <div style={styles.chipsRow}>
          {chips.map((ex, i) => (
            <span key={i} style={styles.chip}>
              {ex.name}
            </span>
          ))}
          {(routine.exercises?.length ?? 0) > 4 && (
            <span style={styles.chipMore}>
              +{routine.exercises.length - 4}
            </span>
          )}
        </div>
      )}

      <div style={styles.cardActions}>
        <button style={styles.primaryBtn} onClick={onStart}>
          <Play size={14} style={{ marginRight: 5 }} />
          Start
        </button>
        <button style={styles.ghostBtn} onClick={onEdit}>
          <Pencil size={14} style={{ marginRight: 5 }} />
          Edit
        </button>
      </div>
    </div>
  );
}

// ── ExerciseBuilderCard ───────────────────────────────────────────────────────

function ExerciseBuilderCard({ ex, exIdx, total, onChange, onRemove, onMoveUp, onMoveDown }) {
  function handleSetChange(setIdx, field, value) {
    const newSets = ex.sets.map((s, i) =>
      i === setIdx ? { ...s, [field]: value } : s
    );
    onChange({ ...ex, sets: newSets });
  }

  function addSet() {
    const last = ex.sets[ex.sets.length - 1] ?? { reps: '', weight: '' };
    onChange({ ...ex, sets: [...ex.sets, { reps: last.reps, weight: last.weight }] });
  }

  function removeSet(setIdx) {
    if (ex.sets.length <= 1) return;
    onChange({ ...ex, sets: ex.sets.filter((_, i) => i !== setIdx) });
  }

  return (
    <div style={styles.builderCard}>
      {/* Header row */}
      <div style={styles.builderCardHeader}>
        <div style={{ flex: 1 }}>
          <div style={styles.builderExName}>{ex.name}</div>
          {ex.bodyPart ? (
            <span style={styles.bodyPartBadge}>{ex.bodyPart}</span>
          ) : null}
        </div>
        <div style={styles.builderCardControls}>
          <span style={styles.setCountBadge}>{ex.sets.length} sets</span>
          <button
            style={{ ...styles.iconBtn, opacity: exIdx === 0 ? 0.3 : 1 }}
            disabled={exIdx === 0}
            onClick={onMoveUp}
            aria-label="Move up"
          >
            <ArrowUp size={14} color="#9CA3AF" />
          </button>
          <button
            style={{ ...styles.iconBtn, opacity: exIdx === total - 1 ? 0.3 : 1 }}
            disabled={exIdx === total - 1}
            onClick={onMoveDown}
            aria-label="Move down"
          >
            <ArrowDown size={14} color="#9CA3AF" />
          </button>
          <button style={styles.iconBtn} onClick={onRemove} aria-label="Remove exercise">
            <X size={14} color="#F87171" />
          </button>
        </div>
      </div>

      {/* Set rows */}
      <div style={styles.builderSetHeader}>
        <span style={{ width: 28, textAlign: 'center' }}>SET</span>
        <span style={{ flex: 1, textAlign: 'center' }}>KG</span>
        <span style={{ flex: 1, textAlign: 'center' }}>REPS</span>
        <span style={{ width: 28 }} />
      </div>
      {ex.sets.map((s, si) => (
        <div key={si} style={styles.builderSetRow}>
          <span style={styles.builderSetNum}>{si + 1}</span>
          <input
            style={styles.setInput}
            type="number"
            inputMode="decimal"
            placeholder="—"
            value={s.weight}
            onChange={e => handleSetChange(si, 'weight', e.target.value)}
          />
          <input
            style={styles.setInput}
            type="number"
            inputMode="numeric"
            placeholder="—"
            value={s.reps}
            onChange={e => handleSetChange(si, 'reps', e.target.value)}
          />
          <button
            style={{ ...styles.iconBtn, opacity: ex.sets.length <= 1 ? 0.3 : 1 }}
            disabled={ex.sets.length <= 1}
            onClick={() => removeSet(si)}
            aria-label="Remove set"
          >
            <X size={12} color="#6B7280" />
          </button>
        </div>
      ))}

      {/* Add Set */}
      <button style={styles.addSetBtn} onClick={addSet}>
        + Add Set
      </button>
    </div>
  );
}

// ── BuilderView ───────────────────────────────────────────────────────────────

function BuilderView({ initial, onBack, onSaved }) {
  const [routine, setRoutine] = useState(() =>
    initial ? { ...initial, exercises: initial.exercises.map(e => ({ ...e, sets: e.sets?.length ? e.sets : [{ reps: '', weight: '' }] })) } : makeEmptyRoutine()
  );
  const [showPicker, setShowPicker] = useState(false);
  const [saving, setSaving] = useState(false);
  const [saveError, setSaveError] = useState(null);

  const isNew = !initial;

  function updateExercise(idx, updated) {
    setRoutine(r => ({
      ...r,
      exercises: r.exercises.map((e, i) => (i === idx ? updated : e)),
    }));
  }

  function removeExercise(idx) {
    setRoutine(r => ({
      ...r,
      exercises: r.exercises.filter((_, i) => i !== idx),
    }));
  }

  function moveExercise(idx, dir) {
    const target = idx + dir;
    setRoutine(r => {
      if (target < 0 || target >= r.exercises.length) return r;
      const arr = [...r.exercises];
      [arr[idx], arr[target]] = [arr[target], arr[idx]];
      return { ...r, exercises: arr };
    });
  }

  function handlePick(ex) {
    setShowPicker(false);
    setRoutine(r => ({
      ...r,
      exercises: [...r.exercises, makeEmptyExercise(ex)],
    }));
  }

  async function handleSave() {
    if (!routine.title.trim()) return;
    setSaving(true);
    setSaveError(null);
    try {
      await saveRoutine({ ...routine, updatedAt: new Date().toISOString() });
      onSaved();
    } catch (err) {
      setSaveError('Could not save routine. Please try again.');
    } finally {
      setSaving(false);
    }
  }

  return (
    <>
      {/* Scrollable builder layout */}
      <div style={styles.builderContainer}>
        {/* Sticky header */}
        <div style={styles.builderHeader}>
          <button style={styles.backBtn} onClick={onBack} aria-label="Back">
            <ArrowLeft size={20} color="#F9FAFB" />
          </button>
          <div style={styles.builderHeaderTitle}>
            {isNew ? 'New Routine' : routine.title || 'Edit Routine'}
          </div>
        </div>

        {/* Scrollable content */}
        <div className="scroll-past-nav" style={{ flex: 1 }}>
          {/* Name input */}
          <div style={styles.builderSection}>
            <input
              style={styles.routineNameInput}
              placeholder="Routine Name"
              value={routine.title}
              onChange={e => setRoutine(r => ({ ...r, title: e.target.value }))}
              maxLength={80}
            />
          </div>

          {/* Default rest */}
          <div style={styles.restRow}>
            <div style={styles.restLabel}>
              <Clock size={14} color="#9CA3AF" style={{ marginRight: 6 }} />
              Default Rest
            </div>
            <div style={styles.restInputWrap}>
              <input
                style={styles.restInput}
                type="number"
                inputMode="numeric"
                min="0"
                max="600"
                value={routine.defaultRest ?? 90}
                onChange={e =>
                  setRoutine(r => ({ ...r, defaultRest: Number(e.target.value) }))
                }
              />
              <span style={styles.restUnit}>sec</span>
            </div>
          </div>

          {/* Exercise list */}
          {routine.exercises.length === 0 ? (
            <div style={styles.builderEmptyState}>
              No exercises yet. Tap "Add Exercise" below.
            </div>
          ) : (
            <div style={styles.builderExList}>
              {routine.exercises.map((ex, idx) => (
                <ExerciseBuilderCard
                  key={ex.id ?? idx}
                  ex={ex}
                  exIdx={idx}
                  total={routine.exercises.length}
                  onChange={updated => updateExercise(idx, updated)}
                  onRemove={() => removeExercise(idx)}
                  onMoveUp={() => moveExercise(idx, -1)}
                  onMoveDown={() => moveExercise(idx, 1)}
                />
              ))}
            </div>
          )}

          {/* Add Exercise button */}
          <button
            style={styles.addExerciseBtn}
            onClick={() => setShowPicker(true)}
          >
            <Plus size={16} style={{ marginRight: 6 }} />
            Add Exercise
          </button>

          {/* Save button */}
          <button
            style={{
              ...styles.saveBtn,
              opacity: !routine.title.trim() || saving ? 0.45 : 1,
              cursor: !routine.title.trim() || saving ? 'not-allowed' : 'pointer',
            }}
            disabled={!routine.title.trim() || saving}
            onClick={handleSave}
          >
            {saving ? 'Saving…' : 'Save Routine'}
          </button>
          {saveError && (
            <div style={{ color: '#EF4444', fontSize: 13, marginTop: 8, textAlign: 'center', paddingBottom: 8 }}>
              {saveError}
            </div>
          )}
        </div>
      </div>

      {/* Exercise picker — always mounted after first open */}
      <div
        style={{ ...styles.sheetBackdrop, display: showPicker ? 'flex' : 'none' }}
        onClick={() => setShowPicker(false)}
      >
        <div style={styles.sheetPanel} onClick={e => e.stopPropagation()}>
          <div style={styles.sheetHandle} />
          <div style={styles.sheetHeader}>
            <span style={styles.sheetTitle}>Add Exercise</span>
            <button
              style={styles.sheetClose}
              onClick={() => setShowPicker(false)}
              aria-label="Close"
            >
              <X size={20} color="#9CA3AF" />
            </button>
          </div>
          <div style={styles.sheetBody}>
            <ExercisesTab pickerMode onPick={handlePick} />
          </div>
        </div>
      </div>
    </>
  );
}

// ── WorkoutTab (main export) ──────────────────────────────────────────────────

export default function WorkoutTab({ active }) {
  const { startSession } = useWorkout();
  const { settings, routines, sessions, refreshRoutines, dataReady } = useApp();
  const [editing, setEditing] = useState(null);

  const lastDates = useMemo(() => {
    const dates = {};
    for (const s of sessions) {
      if (!s.routineId) continue;
      if (!dates[s.routineId] || s.date > dates[s.routineId]) {
        dates[s.routineId] = s.date;
      }
    }
    return dates;
  }, [sessions]);

  async function handleDelete(id) {
    await deleteRoutine(id);
    refreshRoutines();
  }

  function handleStartEmpty() {
    startSession({ title: 'Quick Workout', exercises: [] }, settings);
  }

  function handleStartRoutine(routine) {
    startSession(routine, settings);
  }

  if (editing !== null) {
    return (
      <BuilderView
        initial={editing === 'new' ? null : editing}
        onBack={() => setEditing(null)}
        onSaved={() => { setEditing(null); refreshRoutines(); }}
      />
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2 style={styles.headerTitle}>Workout</h2>
      </div>

      <div className="scroll-past-nav" style={{ flex: 1 }}>
        {/* Start Empty Workout */}
        <div style={{ padding: '16px 16px 24px' }}>
          <button style={styles.startEmptyBtn} onClick={handleStartEmpty}>
            <Play size={16} style={{ marginRight: 8 }} />
            Start Empty Workout
          </button>
        </div>

        {/* My Routines */}
        <div style={styles.sectionRow}>
          <span style={styles.sectionLabel}>My Routines</span>
          <button style={styles.newRoutineBtn} onClick={() => setEditing('new')}>
            <Plus size={15} style={{ marginRight: 4 }} />
            New Routine
          </button>
        </div>

        {!dataReady ? (
          <div style={styles.emptyState}>Loading…</div>
        ) : routines.length === 0 ? (
          <div style={styles.emptyState}>
            <div style={{ marginBottom: 6 }}>No routines yet.</div>
            <div style={{ fontSize: 13, color: 'var(--text3)' }}>
              Tap "New Routine" to get started.
            </div>
          </div>
        ) : (
          <div style={styles.routineList}>
            {routines.map(routine => (
              <RoutineCard
                key={routine.id}
                routine={routine}
                lastDate={lastDates[routine.id] ?? null}
                onStart={() => handleStartRoutine(routine)}
                onEdit={() => setEditing(routine)}
                onDelete={() => handleDelete(routine.id)}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

