import { useState } from 'react';
import { saveFood } from './db';

export default function CustomFoodModal({ onSaved, onClose }) {
  const [name,     setName]     = useState('');
  const [brand,    setBrand]    = useState('');
  const [kcal,     setKcal]     = useState('');
  const [protein,  setProtein]  = useState('');
  const [carbs,    setCarbs]    = useState('');
  const [fat,      setFat]      = useState('');
  const [fiber,    setFiber]    = useState('');
  const [category, setCategory] = useState('other');
  const [serving,  setServing]  = useState('100');
  const [saving,   setSaving]   = useState(false);
  const [error,    setError]    = useState('');

  const CATEGORIES = ['protein','dairy','grain','vegetable','fruit','fat','beverage','supplement','other'];

  async function handleSave() {
    if (!name.trim()) { setError('Name is required'); return; }
    if (!kcal) { setError('Calories are required'); return; }
    setSaving(true);
    const food = {
      name:         name.trim(),
      brand:        brand.trim() || null,
      category,
      sourceDb:     'custom',
      kcal:         Number(kcal)    || 0,
      proteinG:     Number(protein) || 0,
      carbsG:       Number(carbs)   || 0,
      fatG:         Number(fat)     || 0,
      fiberG:       Number(fiber)   || 0,
      sugarG:       0,
      sodiumMg:     0,
      servingSizeG: Number(serving) || 100,
      isCustom:     true,
    };
    const id = await saveFood(food);
    onSaved({ ...food, id });
  }

  function numField(label, val, setVal, placeholder = '0') {
    return (
      <div className="nc-field-row">
        <span className="nc-field-label">{label}</span>
        <input
          className="nc-field-input"
          type="number" min="0" step="0.1"
          placeholder={placeholder}
          value={val}
          onChange={e => setVal(e.target.value)}
          inputMode="decimal"
        />
      </div>
    );
  }

  return (
    <div className="nc-picker">
      <div className="nc-picker-header">
        <div className="nc-picker-title-row">
          <span className="nc-picker-title">Create Custom Food</span>
          <button className="nc-picker-close" onClick={onClose}>✕</button>
        </div>
      </div>

      <div className="nc-picker-list" style={{ padding: '0 0 16px' }}>
        <div className="nc-goals-screen" style={{ padding: '0 16px' }}>
          {error && (
            <div style={{ background: 'rgba(248,113,113,0.1)', border: '1px solid var(--nc-warn)', borderRadius: 8, padding: '8px 12px', marginBottom: 12, color: 'var(--nc-warn)', fontSize: 13 }}>
              {error}
            </div>
          )}

          <div className="nc-section-title">Food Info</div>
          <div className="nc-card">
            <div className="nc-field-row">
              <span className="nc-field-label">Name *</span>
              <input
                className="nc-field-input" style={{ width: 160 }}
                placeholder="Food name"
                value={name}
                onChange={e => setName(e.target.value)}
              />
            </div>
            <div className="nc-field-row">
              <span className="nc-field-label">Brand</span>
              <input
                className="nc-field-input" style={{ width: 160 }}
                placeholder="Optional"
                value={brand}
                onChange={e => setBrand(e.target.value)}
              />
            </div>
            <div className="nc-field-row">
              <span className="nc-field-label">Category</span>
              <select className="nc-field-select" value={category} onChange={e => setCategory(e.target.value)}>
                {CATEGORIES.map(c => <option key={c} value={c}>{c.charAt(0).toUpperCase() + c.slice(1)}</option>)}
              </select>
            </div>
            <div className="nc-field-row">
              <span className="nc-field-label">Serving size (g)</span>
              <input
                className="nc-field-input"
                type="number" min="1"
                value={serving}
                onChange={e => setServing(e.target.value)}
                inputMode="decimal"
              />
            </div>
          </div>

          <div className="nc-section-title">Nutrition per 100g</div>
          <div className="nc-card">
            {numField('Calories (kcal) *', kcal, setKcal, '0')}
            {numField('Protein (g)',  protein, setProtein)}
            {numField('Carbs (g)',    carbs,   setCarbs)}
            {numField('Fat (g)',      fat,     setFat)}
            {numField('Fiber (g)',    fiber,   setFiber)}
          </div>

          <button className="nc-save-btn" onClick={handleSave} disabled={saving}>
            {saving ? 'Saving…' : 'Save Food'}
          </button>
        </div>
      </div>
    </div>
  );
}
